/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Strategy Cards Page
   Visual card-based strategy explorer with filtering, sorting, and animations
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import useStrategies from '../hooks/useStrategies';
import usePageTitle from '../hooks/usePageTitle';
import useRegions from '../hooks/useRegions';
import { tokens } from '../styles/tokens';
import s from './StrategyCardsPage.module.css';

// ── Design tokens (for dynamic/inline color values) ─────────────────────
const colors = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};

// ── Sort options ────────────────────────────────────────────────────────
const SORT_OPTIONS = [
  { key: 'avg_score',    label: 'Score' },
  { key: 'profit_factor', label: 'Profit Factor' },
  { key: 'avg_win_rate', label: 'Win Rate' },
  { key: 'avg_sharpe',   label: 'Sharpe' },
];

// ── Framer Motion variants ──────────────────────────────────────────────
const containerVariants = {
  hidden: {},
  visible: {
    transition: { staggerChildren: 0.035 },
  },
};

const cardVariants = {
  hidden: { opacity: 0, y: 20, scale: 0.97 },
  visible: {
    opacity: 1, y: 0, scale: 1,
    transition: { duration: 0.25, ease: [0.4, 0, 0.2, 1] },
  },
  exit: {
    opacity: 0, y: -12, scale: 0.97,
    transition: { duration: 0.15 },
  },
};

// ── Win Rate Ring (SVG donut) ───────────────────────────────────────────
function WinRateRing({ value, size = 52 }) {
  const pct = value != null ? Math.max(0, Math.min(100, value)) : 0;
  const radius = (size - 6) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (pct / 100) * circumference;
  const ringColor = pct >= 60 ? colors.green : pct >= 50 ? colors.amber : colors.red;

  return (
    <div className={s.ringWrapper} style={{ width: size, height: size }}>
      <svg width={size} height={size} className={s.ringSvg}>
        {/* Background track */}
        <circle
          cx={size / 2} cy={size / 2} r={radius}
          fill="none" stroke={colors.surface2} strokeWidth={4}
        />
        {/* Filled arc */}
        {value != null && (
          <circle
            cx={size / 2} cy={size / 2} r={radius}
            fill="none" stroke={ringColor} strokeWidth={4}
            strokeDasharray={circumference}
            strokeDashoffset={offset}
            strokeLinecap="round"
            className={s.ringArc}
          />
        )}
      </svg>
      <div className={s.ringLabel} style={{
        color: value != null ? ringColor : colors.textSecondary,
      }}>
        {value != null ? `${value}%` : '--'}
      </div>
    </div>
  );
}

// ── Metric Bar (horizontal) ─────────────────────────────────────────────
function MetricBar({ value, max, color, label }) {
  const pct = value != null && max > 0 ? Math.min((value / max) * 100, 100) : 0;
  return (
    <div className={s.metricBarContainer}>
      <div className={s.metricBarHeader}>
        <span className={s.metricBarLabel}>{label}</span>
        <span className={s.metricBarValue} style={{ color: color || colors.textPrimary }}>
          {value != null ? (typeof value === 'number' ? value.toFixed(2) : value) : '--'}
        </span>
      </div>
      <div className={s.metricBarTrack}>
        <div className={s.metricBarFill} style={{
          width: `${pct}%`,
          background: color || colors.blue,
        }} />
      </div>
    </div>
  );
}

// ── Direction Badge ─────────────────────────────────────────────────────
function DirectionBadge({ direction }) {
  const d = (direction || '').toLowerCase();
  const isLong = d === 'long';
  const isShort = d === 'short';
  const cls = isLong ? s.dirBadgeLong : isShort ? s.dirBadgeShort : s.dirBadgeDefault;
  return (
    <span className={`${s.dirBadge} ${cls}`}>
      {direction || 'N/A'}
    </span>
  );
}

// ── Region Pill ─────────────────────────────────────────────────────────
function RegionPill({ region }) {
  return (
    <span className={s.regionPill}>
      {region || 'US'}
    </span>
  );
}

// ── Sparkline (from StrategyCataloguePage, adapted) ─────────────────────
function MiniSparkline({ winRate, avgReturn, trades, width = 100, height = 28 }) {
  if (!trades || trades < 3) return <div className={s.sparklinePlaceholder} style={{ width, height }} />;
  const wr = (winRate || 50) / 100;
  const ret = avgReturn || 0.02;
  const pts = Math.min(trades, 40);
  const curve = [100];
  for (let i = 1; i <= pts; i++) {
    const win = (i / pts) < wr;
    const r = win ? Math.abs(ret) * 0.8 : -Math.abs(ret) * 0.6;
    const jitter = Math.sin(i * 5.7 + (winRate || 0)) * 0.004;
    curve.push(curve[curve.length - 1] * (1 + r + jitter));
  }
  const sorted = [...curve].sort((a, b) => a - b);
  const final = curve.map((v, i) => {
    const progress = i / curve.length;
    return sorted[0] + (sorted[sorted.length - 1] - sorted[0]) * progress + (v - curve[0]) * 0.25;
  });
  const min = Math.min(...final);
  const max = Math.max(...final);
  const range = max - min || 1;
  const isUp = final[final.length - 1] >= final[0];
  const color = isUp ? colors.green : colors.red;
  const d = final.map((v, i) =>
    `${i === 0 ? 'M' : 'L'}${(final.length > 1 ? i / (final.length - 1) * width : 0).toFixed(1)},${(height - 2 - ((v - min) / range) * (height - 4)).toFixed(1)}`
  ).join(' ');
  return (
    <svg width={width} height={height} className={s.sparklineSvg}>
      <defs>
        <linearGradient id={`spark-${isUp ? 'up' : 'dn'}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.3" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={`${d} L${width},${height} L0,${height} Z`} fill={`url(#spark-${isUp ? 'up' : 'dn'})`} />
      <path d={d} fill="none" stroke={color} strokeWidth="1.5" strokeLinejoin="round" />
    </svg>
  );
}

// ═════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═════════════════════════════════════════════════════════════════════════
export default function StrategyCardsPage() {
  usePageTitle('Strategy Cards');
  const navigate = useNavigate();
  const { regions: dynamicRegions } = useRegions();
  const REGIONS = dynamicRegions.map(r => ({ key: r.key, label: r.label, flag: r.key.toUpperCase().slice(0, 2) }));

  // ── State ─────────────────────────────────────────────────────────────
  const [region, setRegion] = useState('us');
  const { strategies, loading } = useStrategies(region);
  const [dirFilter, setDirFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState('avg_score');
  const [sortDir, setSortDir] = useState('desc');

  const handleSort = useCallback((key) => {
    if (sortBy === key) {
      setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    } else {
      setSortBy(key);
      setSortDir('desc');
    }
  }, [sortBy]);

  // ── Computed: max values for bar normalization ────────────────────────
  const maxValues = useMemo(() => {
    if (!strategies || strategies.length === 0) return { pf: 3, sharpe: 3 };
    let maxPf = 0, maxSharpe = 0;
    for (const st of strategies) {
      const stats = st.stats || {};
      const pf = stats.profit_factor ?? stats.avg_pf ?? 0;
      const sh = stats.avg_sharpe ?? 0;
      if (pf > maxPf) maxPf = pf;
      if (sh > maxSharpe) maxSharpe = sh;
    }
    return { pf: Math.max(maxPf, 1), sharpe: Math.max(maxSharpe, 1) };
  }, [strategies]);

  // ── Filtered + Sorted ────────────────────────────────────────────────
  const filtered = useMemo(() => {
    if (!strategies) return [];
    let list = strategies;

    // Direction filter
    if (dirFilter !== 'all') {
      list = list.filter(st => st.direction && st.direction.toLowerCase() === dirFilter);
    }

    // Search
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(st => {
        const label = (st.label || st.name || '').toLowerCase();
        return label.includes(q);
      });
    }

    // Sort
    list = [...list].sort((a, b) => {
      const aStats = a.stats || {};
      const bStats = b.stats || {};
      let av, bv;
      if (sortBy === 'profit_factor') {
        av = aStats.profit_factor ?? aStats.avg_pf ?? -Infinity;
        bv = bStats.profit_factor ?? bStats.avg_pf ?? -Infinity;
      } else {
        av = aStats[sortBy] ?? -Infinity;
        bv = bStats[sortBy] ?? -Infinity;
      }
      return sortDir === 'desc' ? bv - av : av - bv;
    });

    return list;
  }, [strategies, dirFilter, search, sortBy, sortDir]);

  const totalCount = strategies ? strategies.length : 0;
  const longCount = strategies ? strategies.filter(st => (st.direction || '').toLowerCase() === 'long').length : 0;
  const shortCount = strategies ? strategies.filter(st => (st.direction || '').toLowerCase() === 'short').length : 0;

  // ── Loading state ─────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className={`page-container ${s.loadingContainer}`}>
        <div className={s.loadingInner}>
          <motion.div
            animate={{ rotate: 360 }}
            transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
            className={s.spinner}
          />
          <span className={s.loadingText}>Loading strategies...</span>
        </div>
      </div>
    );
  }

  return (
    <div className={`page-container scrollbar-thin ${s.page}`}>

      {/* ── Header ──────────────────────────────────────────────────── */}
      <div className={s.header}>
        <h1 className={s.title}>Strategy Cards</h1>
        <span className={s.badgeBlue}>{totalCount} strategies</span>
        <span className={s.badgeGreen}>{longCount} long</span>
        <span className={s.badgeRed}>{shortCount} short</span>
      </div>

      {/* ── Filter Bar ──────────────────────────────────────────────── */}
      <div className={s.filterBar}>
        {/* Search */}
        <div className={s.searchWrapper}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={colors.textSecondary} strokeWidth="2"
            className={s.searchIcon}>
            <circle cx="11" cy="11" r="8" /><path d="M21 21l-4.35-4.35" />
          </svg>
          <input
            type="text"
            placeholder="Search strategies..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className={s.searchInput}
          />
        </div>

        {/* Divider */}
        <div className={s.divider} />

        {/* Direction filter */}
        <div className={s.filterGroup}>
          <span className={s.filterLabel}>Dir</span>
          {[
            { key: 'all', label: 'All' },
            { key: 'long', label: 'Long' },
            { key: 'short', label: 'Short' },
          ].map(opt => {
            const active = dirFilter === opt.key;
            const c = opt.key === 'long' ? colors.green : opt.key === 'short' ? colors.red : colors.blue;
            return (
              <button
                key={opt.key}
                onClick={() => setDirFilter(opt.key)}
                className={s.filterBtn}
                style={{
                  borderColor: active ? c : undefined,
                  background: active ? `${c}18` : undefined,
                  color: active ? c : undefined,
                }}
              >
                {opt.label}
              </button>
            );
          })}
        </div>

        {/* Divider */}
        <div className={s.divider} />

        {/* Region */}
        <div className={s.filterGroup}>
          <span className={s.filterLabel}>Region</span>
          {REGIONS.map(r => {
            const active = region === r.key;
            return (
              <button
                key={r.key}
                onClick={() => setRegion(r.key)}
                className={s.filterBtn}
                style={{
                  borderColor: active ? colors.amber : undefined,
                  background: active ? 'rgba(245,158,11,0.15)' : undefined,
                  color: active ? colors.amber : undefined,
                }}
              >
                {r.label}
              </button>
            );
          })}
        </div>

        {/* Divider */}
        <div className={s.divider} />

        {/* Sort */}
        <div className={s.filterGroupWrap}>
          <span className={s.filterLabel}>Sort</span>
          {SORT_OPTIONS.map(opt => {
            const active = sortBy === opt.key;
            return (
              <button
                key={opt.key}
                onClick={() => handleSort(opt.key)}
                className={s.sortBtn}
                style={{
                  borderColor: active ? colors.cyan : undefined,
                  background: active ? 'rgba(34,211,238,0.1)' : undefined,
                  color: active ? colors.cyan : undefined,
                }}
              >
                {opt.label}
                {active && (
                  <span className={s.sortArrow}>{sortDir === 'desc' ? '\u25BC' : '\u25B2'}</span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* ── Results count ───────────────────────────────────────────── */}
      <div className={s.resultsRow}>
        <span className={s.resultsCount}>
          {filtered.length} {filtered.length === 1 ? 'strategy' : 'strategies'} shown
        </span>
        <button
          onClick={() => navigate('/strategies')}
          className={s.tableViewBtn}
        >
          Table View &rarr;
        </button>
      </div>

      {/* ── Card Grid ───────────────────────────────────────────────── */}
      <AnimatePresence mode="wait">
        <motion.div
          key={`${region}-${dirFilter}-${sortBy}-${sortDir}`}
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          exit="hidden"
          className={s.cardGrid}
        >
          {filtered.length > 0 ? (
            filtered.map((strategy, idx) => {
              const stats = strategy.stats || {};
              const trades = stats.total_trades || 0;
              const winRate = stats.avg_win_rate;
              const profitFactor = stats.profit_factor ?? stats.avg_pf;
              const sharpe = stats.avg_sharpe;
              const score = stats.avg_score;
              const avgReturn = stats.avg_return;

              const pfColor = profitFactor != null
                ? (profitFactor >= 2 ? colors.green : profitFactor >= 1.3 ? colors.amber : colors.red)
                : colors.textSecondary;

              const sharpeColor = sharpe != null
                ? (sharpe >= 1.5 ? colors.green : sharpe >= 0.8 ? colors.amber : colors.red)
                : colors.textSecondary;

              return (
                <motion.div
                  key={strategy.key || strategy.name || idx}
                  variants={cardVariants}
                  layout
                  onClick={() => navigate(`/strategies/${encodeURIComponent(strategy.key || strategy.name || strategy.label)}`)}
                  whileHover={{
                    y: -4,
                    boxShadow: '0 12px 40px rgba(0,0,0,0.4)',
                    borderColor: 'rgba(96,165,250,0.3)',
                  }}
                  whileTap={{ scale: 0.98 }}
                  className={s.card}
                >
                  {/* Card Header */}
                  <div className={s.cardHeader}>
                    {/* Rank badge */}
                    <span className={`${s.rankBadge} ${idx < 3 ? s.rankBadgeTop : s.rankBadgeDefault}`}>
                      {idx + 1}
                    </span>

                    {/* Name */}
                    <div className={s.cardNameWrap}>
                      <div className={s.cardName}>
                        {strategy.label}
                      </div>
                      {strategy.category && strategy.category !== 'equity' && (
                        <span className={s.categoryBadge}>
                          {strategy.category}
                        </span>
                      )}
                    </div>

                    {/* Direction + Region */}
                    <div className={s.cardBadges}>
                      <RegionPill region={region.toUpperCase()} />
                      <DirectionBadge direction={strategy.direction} />
                    </div>
                  </div>

                  {/* Sparkline + Win Rate Ring */}
                  <div className={s.sparklineRow}>
                    <WinRateRing value={winRate} size={54} />
                    <div className={s.sparklineCol}>
                      <MiniSparkline
                        winRate={winRate}
                        avgReturn={avgReturn}
                        trades={trades}
                        width={180}
                        height={32}
                      />
                      <div className={s.sparklineMeta}>
                        <span className={s.metaText}>
                          {trades.toLocaleString()} trades
                        </span>
                        {score != null && (
                          <span className={s.scoreBadge} style={{
                            color: score >= 20 ? colors.green : score >= 10 ? colors.amber : colors.textSecondary,
                          }}>
                            Score: {score.toFixed(1)}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Metric Bars */}
                  <div className={s.metricBarsRow}>
                    <MetricBar
                      label="Profit Factor"
                      value={profitFactor}
                      max={maxValues.pf}
                      color={pfColor}
                    />
                    <MetricBar
                      label="Sharpe"
                      value={sharpe}
                      max={maxValues.sharpe}
                      color={sharpeColor}
                    />
                  </div>

                  {/* Bottom Stats Row */}
                  <div className={s.bottomStats}>
                    {[
                      {
                        label: 'Win Rate',
                        value: winRate,
                        fmt: v => `${v}%`,
                        c: winRate != null ? (winRate >= 60 ? colors.green : winRate >= 50 ? colors.amber : colors.red) : colors.textSecondary,
                      },
                      {
                        label: 'PF',
                        value: profitFactor,
                        fmt: v => v.toFixed(2),
                        c: pfColor,
                      },
                      {
                        label: 'Sharpe',
                        value: sharpe,
                        fmt: v => v.toFixed(2),
                        c: sharpeColor,
                      },
                      {
                        label: 'Return',
                        value: avgReturn,
                        fmt: v => `${(v * 100).toFixed(1)}%`,
                        c: avgReturn != null ? (avgReturn >= 0.03 ? colors.green : avgReturn > 0 ? colors.amber : colors.red) : colors.textSecondary,
                      },
                    ].map(m => (
                      <div key={m.label} className={s.bottomStatCell}>
                        <div className={s.bottomStatLabel}>{m.label}</div>
                        <div className={s.bottomStatValue} style={{ color: m.c }}>
                          {m.value != null ? m.fmt(m.value) : '--'}
                        </div>
                      </div>
                    ))}
                  </div>
                </motion.div>
              );
            })
          ) : (
            <motion.div
              variants={cardVariants}
              className={s.emptyState}
            >
              No strategies match your filters.
            </motion.div>
          )}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}
